using UnityEngine;
using FL.Gameplay.Modules.BigWorld;
using System.Reflection;
public class Script
{
    public static object Main()
    {
        var sb = new System.Text.StringBuilder();
        var dmType = typeof(FL.Gameplay.Modules.BigWorld.DataManager);
        var instProp = dmType.GetProperty("Instance", BindingFlags.Public | BindingFlags.Static);
        if (instProp == null) { return "No Instance property on DataManager"; }
        var dm = instProp.GetValue(null);
        if (dm == null) { return "DataManager.Instance is null"; }
        var field = dmType.GetField("_npc_data", BindingFlags.NonPublic | BindingFlags.Instance);
        if (field == null) { return "_npc_data field not found"; }
        var dict = field.GetValue(dm);
        if (dict == null) { return "_npc_data is null"; }
        var countProp = dict.GetType().GetProperty("Count");
        int count = countProp != null ? (int)countProp.GetValue(dict) : -1;
        sb.AppendLine("_npc_data count: " + count);
        // Also check town and sakura
        var townField = dmType.GetField("_townNpc_data", BindingFlags.NonPublic | BindingFlags.Instance);
        var sakuraField = dmType.GetField("_sakuraNpc_data", BindingFlags.NonPublic | BindingFlags.Instance);
        var townDict = townField?.GetValue(dm);
        var sakuraDict = sakuraField?.GetValue(dm);
        int townCount = (int)(townDict?.GetType().GetProperty("Count")?.GetValue(townDict) ?? -1);
        int sakuraCount = (int)(sakuraDict?.GetType().GetProperty("Count")?.GetValue(sakuraDict) ?? -1);
        sb.AppendLine("_townNpc_data count: " + townCount);
        sb.AppendLine("_sakuraNpc_data count: " + sakuraCount);
        // Check waitingRemove
        var waitField = dmType.GetField("_npc_waitingRemove", BindingFlags.NonPublic | BindingFlags.Instance);
        var waitSet = waitField?.GetValue(dm);
        int waitCount = (int)(waitSet?.GetType().GetProperty("Count")?.GetValue(waitSet) ?? -1);
        sb.AppendLine("_npc_waitingRemove count: " + waitCount);
        return sb.ToString();
    }
}
